23	architecture sim of en_cl_fix_pkg_tb is
24	
25		-- Define VHDL-2008 equivalent for tools that are not VHDL 2008 capable (e.g. vivado simulator)
26		function to_string( a: std_logic_vector) return string is
27			variable b : string (1 to a'length) := (others => NUL);
28			variable stri : integer := 1; 
29		begin
30			for i in a'range loop
31				b(stri) := std_logic'image(a((i)))(2);
32				stri := stri+1;
33			end loop;
34			return b;
35		end function;
36	
37		procedure CheckStdlv(	expected : std_logic_vector;
38								actual	 : std_logic_vector;
39								msg		 : string) is
40		begin
41			assert expected = actual
42				report "###ERROR### " & msg & " [expected: " & to_string(expected) & ", got: " & to_string(actual) & "]"
43				severity error;
44		end procedure;
45		
46		
47		procedure CheckInt(	expected : integer;
48							actual	 : integer;
49							msg		 : string) is
50		begin
51			assert expected = actual
52				report "###ERROR### " & msg & " [expected: " & integer'image(expected) & ", got: " & integer'image(actual) & "]"
53				severity error;
54		end procedure;	
55		
56		procedure CheckReal(	expected : real;
57								actual	 : real;
58								msg		 : string) is
59		begin
60			assert expected < actual + 1.0e-12 and expected > actual - 1.0e-12
61				report "###ERROR### " & msg & " [expected: " & real'image(expected) & ", got: " & real'image(actual) & "]"
62				severity error;
63		end procedure;	
64	
65		procedure CheckStdl(	expected : std_logic;
66								actual	 : std_logic;
67								msg		 : string) is
68		begin
69			assert expected = actual
70				report "###ERROR### " & msg & " [expected: " & std_logic'image(expected) & ", got: " & std_logic'image(actual) & "]"
71				severity error;
72		end procedure;		
73		
74		procedure CheckBoolean(	expected : boolean;
75								actual	 : boolean;
76								msg		 : string) is
77		begin
78			assert expected = actual
79				report "###ERROR### " & msg & " [expected: " & boolean'image(expected) & ", got: " & boolean'image(actual) & "]"
80				severity error;
81		end procedure;		
82	
83		procedure print(text : string) is
84			variable l : line;
85		begin
86			write(l, text);
87			writeline(output, l);
88		end procedure;
89	
90	begin
91	
92		-------------------------------------------------------------------------
93		-- TB Control
94		-------------------------------------------------------------------------
95		p_control : process
96		begin
97			-- *** cl_fix_width ***
98			print("*** cl_fix_width ***");
99			CheckInt(3, cl_fix_width((false, 3, 0)), 	"cl_fix_width Wrong: Integer only, Unsigned, NoFractional Bits");
100			CheckInt(4, cl_fix_width((true, 3, 0)), 	"cl_fix_width Wrong: Integer only, Signed, NoFractional Bits");
101			CheckInt(3, cl_fix_width((false, 0, 3)), 	"cl_fix_width Wrong: Fractional only, Unsigned, No Integer Bits");
102			CheckInt(4, cl_fix_width((true, 0, 3)), 	"cl_fix_width Wrong: Fractional only, Signed, No Integer Bits");
103			CheckInt(7, cl_fix_width((true, 3, 3)), 	"cl_fix_width Wrong: Integer and Fractional Bits");
104			CheckInt(2, cl_fix_width((true, -2, 3)),	"cl_fix_width Wrong: Negative integer bits");
105			CheckInt(2, cl_fix_width((true, 3, -2)), 	"cl_fix_width Wrong: Negative fractional bits");
106		
107			-- *** cl_fix_from_real ***
108			print("*** cl_fix_from_real ***");
109			CheckStdlv(	"0011", 	
110						cl_fix_from_real(	3.0, (true, 3, 0)), 
111						"cl_fix_from_real Wrong: Integer only, Signed, NoFractional Bits, Positive");
112			CheckStdlv(	"1101", 	
113						cl_fix_from_real(	-3.0, (true, 3, 0)), 
114						"cl_fix_from_real Wrong: Integer only, Signed, NoFractional Bits, Negative");			
115			CheckStdlv(	"011", 	
116						cl_fix_from_real(	3.0, (false, 3, 0)), 
117						"cl_fix_from_real Wrong: Integer only, Unsigned, NoFractional Bits, Positive");
118			CheckStdlv(	"110011", 	
119						cl_fix_from_real(	-3.25, (true, 3, 2)), 
120						"cl_fix_from_real Wrong: Integer and Fractional");	
121			CheckStdlv(	"11010", 	
122						cl_fix_from_real(	-3.24, (true, 3, 1)), 
123						"cl_fix_from_real Wrong: Rounding");	
124			CheckStdlv(	"01", 	
125						cl_fix_from_real(	0.125, (false, -1, 3)), 
126						"cl_fix_from_real Wrong: Negative Integer Bits");	
127			CheckStdlv(	"010", 	
128						cl_fix_from_real(	4.0, (true, 3, -1)), 
129						"cl_fix_from_real Wrong: Negative Fractional Bits");	
130						
131			-- *** cl_fix_to_real ***
132			print("*** cl_fix_to_real ***");
133			CheckReal(	3.0, 	
134						cl_fix_to_real(cl_fix_from_real(	3.0, (true, 3, 0)), (true, 3, 0)), 
135						"cl_fix_to_real Wrong: Integer only, Signed, NoFractional Bits, Positive");
136			CheckReal(	-3.0, 	
137						cl_fix_to_real(cl_fix_from_real(	-3.0, (true, 3, 0)), (true, 3, 0)),
138						"cl_fix_to_real Wrong: Integer only, Signed, NoFractional Bits, Negative");			
139			CheckReal(	3.0, 	
140						cl_fix_to_real(cl_fix_from_real(	3.0, (false, 3, 0)), (false, 3, 0)),
141						"cl_fix_to_real Wrong: Integer only, Unsigned, NoFractional Bits, Positive");
142			CheckReal(	-3.25, 	
143						cl_fix_to_real(cl_fix_from_real(	-3.25, (true, 3, 2)), (true, 3, 2)),
144						"cl_fix_to_real Wrong: Integer and Fractional");	
145			CheckReal(	-3.0, 	
146						cl_fix_to_real(cl_fix_from_real(	-3.24, (true, 3, 1)), (true, 3, 1)),
147						"cl_fix_to_real Wrong: Rounding");	
148			CheckReal(	0.125, 	
149						cl_fix_to_real(cl_fix_from_real(	0.125, (false, -1, 3)), (false, -1, 3)),
150						"cl_fix_to_real Wrong: Negative Integer Bits");	
151			CheckReal(	4.0, 	
152						cl_fix_to_real(cl_fix_from_real(	4.0, (true, 3, -1)), (true, 3, -1)),
153						"cl_fix_to_real Wrong: Negative Fractional Bits");		
154						
155			-- *** cl_fix_from_bits_as_int ***
156			print("*** cl_fix_from_bits_as_int ***");
157			CheckStdlv("0011", cl_fix_from_bits_as_int(3, (false, 4, 0)), "cl_fix_from_bits_as_int: Unsigned Positive");
158			CheckStdlv("0011", cl_fix_from_bits_as_int(3, (true, 3, 0)), "cl_fix_from_bits_as_int: Signed Positive");
159			CheckStdlv("1101", cl_fix_from_bits_as_int(-3, (true, 3, 0)), "cl_fix_from_bits_as_int: Signed Negative");
160			CheckStdlv("1101", cl_fix_from_bits_as_int(-3, (true, 1, 2)), "cl_fix_from_bits_as_int: Fractional"); -- binary point position is not important
161			CheckStdlv("0001", cl_fix_from_bits_as_int(17, (false, 4, 0)), "cl_fix_from_bits_as_int: Wrap Unsigned");		
162			
163			-- *** cl_fix_get_bits_as_int ***
164			print("*** cl_fix_get_bits_as_int ***");
165			CheckInt(3, cl_fix_get_bits_as_int("11", (false,2,0)), "cl_fix_get_bits_as_int: Unsigned Positive");
166			CheckInt(3, cl_fix_get_bits_as_int("011", (true,2,0)), "cl_fix_get_bits_as_int: Signed Positive");
167			CheckInt(-3, cl_fix_get_bits_as_int("1101", (true,3,0)), "cl_fix_get_bits_as_int: Signed Negative");
168			CheckInt(-3, cl_fix_get_bits_as_int("1101", (true,1,2)), "cl_fix_get_bits_as_int: Fractional"); -- binary point position is not important
169	
170			-- *** cl_fix_resize ***
171			print("*** cl_fix_resize ***");
172			CheckStdlv(	"0101", cl_fix_resize("0101", (true, 2, 1), (true, 2, 1)), 
173						"cl_fix_resize: No formatchange");
174						
175			CheckStdlv(	"010", cl_fix_resize("0101", (true, 2, 1), (true, 2, 0), Trunc_s), 
176						"cl_fix_resize: Remove Frac Bit 1 Trunc");
177			CheckStdlv(	"011", cl_fix_resize("0101", (true, 2, 1), (true, 2, 0), Round_s), 
178						"cl_fix_resize: Remove Frac Bit 1 Round");
179			CheckStdlv(	"010", cl_fix_resize("0100", (true, 2, 1), (true, 2, 0), Trunc_s), 
