181			CheckStdlv(	"010", cl_fix_resize("0100", (true, 2, 1), (true, 2, 0), Round_s), 
182						"cl_fix_resize: Remove Frac Bit 0 Round");	
183						
184			CheckStdlv(	"01000", cl_fix_resize("0100", (true, 2, 1), (true, 2, 2), Round_s), 
185						"cl_fix_resize: Add Fractional Bit Signed");	
186			CheckStdlv(	"1000", cl_fix_resize("100", (false, 2, 1), (false, 2, 2), Round_s), 
187						"cl_fix_resize: Add Fractional Bit Unsigned");	
188	
189			CheckStdlv(	"0111", cl_fix_resize("00111", (true, 3, 1), (true, 2, 1), Trunc_s, None_s), 
190						"cl_fix_resize: Remove Integer Bit, Signed, NoSat, Positive");
