198						"cl_fix_resize: Remove Integer Bit, Signed, Sat, Positive");
199			CheckStdlv(	"1000", cl_fix_resize("10011", (true, 3, 1), (true, 2, 1), Trunc_s, Sat_s), 
200						"cl_fix_resize: Remove Integer Bit, Signed, Sat, Negative");
201						
202			CheckStdlv(	"111", cl_fix_resize("0111", (false, 3, 1), (false, 2, 1), Trunc_s, None_s), 
