221						"cl_fix_resize: Overflow due rounding, Unsigned, Wrap");
222			CheckStdlv(	"111", cl_fix_resize("1111", (false, 3, 1), (false, 3, 0), Round_s, Sat_s), 
223						"cl_fix_resize: Overflow due rounding, Unsigned, Sat");
224						
225			CheckStdlv(	"1111", cl_fix_resize("11111", (true, 3, 1), (true, 3, 0), NonSymNeg_s, None_s), 
226						"cl_fix_resize: NonSymNeg_s -0.5");		
227			CheckStdlv(	"1110", cl_fix_resize("11101", (true, 3, 1), (true, 3, 0), NonSymNeg_s, None_s), 
228						"cl_fix_resize: NonSymNeg_s -1.5");		
229			CheckStdlv(	"0000", cl_fix_resize("00001", (true, 3, 1), (true, 3, 0), NonSymNeg_s, None_s), 
230						"cl_fix_resize: NonSymNeg_s 0.5");		
231			CheckStdlv(	"0001", cl_fix_resize("00011", (true, 3, 1), (true, 3, 0), NonSymNeg_s, None_s), 
232						"cl_fix_resize: NonSymNeg_s 1.5");		
233			CheckStdlv(	"0010", cl_fix_resize("000111", (true, 3, 2), (true, 3, 0), NonSymNeg_s, None_s), 
234						"cl_fix_resize: NonSymNeg_s 1.75");						
235	
236			CheckStdlv(	"1111", cl_fix_resize("11111", (true, 3, 1), (true, 3, 0), SymInf_s, None_s), 
237						"cl_fix_resize: SymInf_s -0.5");		
238			CheckStdlv(	"1110", cl_fix_resize("11101", (true, 3, 1), (true, 3, 0), SymInf_s, None_s), 
239						"cl_fix_resize: SymInf_s -1.5");		
240			CheckStdlv(	"0001", cl_fix_resize("00001", (true, 3, 1), (true, 3, 0), SymInf_s, None_s), 
