287			-- *** cl_fix_add ***
288			print("*** cl_fix_add ***");					
289			CheckStdlv(	cl_fix_from_real(-2.5+1.25, (true, 5, 3)), 
290						cl_fix_add(	cl_fix_from_real(-2.5, (true, 5, 3)), (true, 5, 3),
